// ─── Substack Feed Loader ─────────────────────────────────
// Reads from /posts.json — generated by GitHub Actions.
// No CORS issues, no third-party dependencies.

const SUBSTACK_URL = "https://securitytranslated.substack.com";

(async function loadSubstackFeed() {
  const container = document.getElementById("substack-posts");
  if (!container) return;

  try {
    const res = await fetch("/posts.json");

    if (!res.ok) throw new Error(`posts.json returned ${res.status}`);

    const posts = await res.json();

    if (!Array.isArray(posts) || !posts.length) {
      throw new Error("posts.json is empty.");
    }

    container.innerHTML = "";

    posts.forEach(post => {
      const article = document.createElement("article");
      article.className = "blog-post-preview";

      article.innerHTML = `
        <a href="${post.url}" target="_blank" rel="noopener noreferrer" class="post-preview-link">
          <span class="post-preview-date">${post.date}</span>
          <h3>${escapeHtml(post.title)}</h3>
          <p>${escapeHtml(post.excerpt)}${post.excerpt.length >= 200 ? "…" : ""}</p>
          <span class="read-more">Read more →</span>
        </a>
      `;

      container.appendChild(article);
    });

  } catch (err) {
    console.error("Feed load error:", err);
    container.innerHTML = `
      <p class="feed-error">
        Couldn't load posts right now.
        <a href="${SUBSTACK_URL}" target="_blank" rel="noopener">Read them on Substack instead →</a>
      </p>
    `;
  }
})();

function escapeHtml(str) {
  const el = document.createElement("div");
  el.appendChild(document.createTextNode(str || ""));
  return el.innerHTML;
}